using UnityEngine; using UnityEngine.UI; [RequireComponent(typeof(RawImage))] public class BackroomsVHS : MonoBehaviour { private RawImage image; private Texture2D texture; private Color32[] pixels; private int width = 256; private int height = 256; private void Awake(){ image = GetComponent<RawImage>(); texture = new Texture2D(width, height, TextureFormat.RGBA32, false); texture.wrapMode = TextureWrapMode.Clamp; pixels = new Color32[width * height]; image.texture = texture; image.color = new Color(1f, 1f, 1f, 0.055f); } private void Update(){ for (int y = 0; y < height; y++){ byte scan = (byte)(Mathf.PerlinNoise(0f, (y + Time.time * 90f) * 0.03f) * 18f); for (int x = 0; x < width; x++){ byte n = (byte)(Mathf.PerlinNoise((x + Time.time * 35f) * 0.04f, y * 0.04f) * 25f); byte v = (byte)Mathf.Clamp(scan + n, 0, 35); pixels[y * width + x] = new Color32(v, v, v, v); } } texture.SetPixels32(pixels); texture.Apply(false); } }